"""
Dataset metadata constants and lookup tables for CLAIRE-KG.

Provides cached counts, role names, and UID→name/description mappings for small
datasets so the app can avoid repeated Neo4j queries. Large datasets (e.g. CVE,
Vulnerability, Asset) are queried dynamically; small ones (WorkRole, Tactic,
Weakness, AttackPattern, Technique, SubTechnique, Ability, SpecialtyArea) use
these constants.

Main uses:
  - question_classifier: WORKROLE_METADATA["role_names"] for exact work-role matching.
  - database.get_status: *_METADATA total_count for small datasets; live query for large.
  - normalizer/validator: get_standard_field_value, record_has_work_role_shape, STANDARD_FIELD_CANDIDATES.
  - Cypher/schema: CWE_UID_TO_NAME, TACTIC_UID_TO_NAME, CAPEC_UID_TO_* etc. for lookups.

Constants: SMALL_DATASET_THRESHOLD, STANDARD_FIELD_CANDIDATES, WORKROLE_METADATA,
SPECIALTYAREA_METADATA, TACTIC_METADATA, ABILITY_METADATA, DCWF_NICE_MAPPINGS,
CWE_UID_TO_NAME / CWE_UID_TO_DESCRIPTION, TACTIC_UID_TO_*, TECHNIQUE_UID_TO_*,
CAPEC_UID_TO_*, and compact *_METADATA dicts for get_status/is_small_dataset.

API: get_standard_field_value, record_has_work_role_shape, get_workrole_count,
get_workrole_count_by_source, get_workrole_property_coverage, get_workrole_relationship_stats,
is_small_dataset, get_dataset_metadata.

Update this file when datasets are re-ingested.
"""

from typing import Any, Dict, List

# -----------------------------------------------------------------------------
# Threshold and standard field candidates (for normalizer/validator)
# -----------------------------------------------------------------------------

# Datasets with fewer than this many nodes are candidates for cached metadata
SMALL_DATASET_THRESHOLD = 500

# Logical uid/title/text -> possible DB property names (schema-aware result handling)
# Used by normalizer and validator so result processing uses CLAIRE-KG's schema knowledge
# instead of hardcoding. Aligns with schema_knowledge field_mappings + node-type specifics
# (e.g. WorkRole: work_role, definition, dcwf_code; Task: dcwf_number).
STANDARD_FIELD_CANDIDATES: Dict[str, List[str]] = {
    "uid": [
        "uid",
        "id",
        "identifier",
        "dcwf_code",  # WorkRole/DCWF
        "dcwf_number",  # Task/DCWF
        "element_identifier",
        "element_code",
        "AttackPatternID",
        "TechniqueID",
    ],
    "title": [
        "title",
        "name",
        "role_name",  # WorkRole Cypher RETURN AS role_name
        "work_role",  # WorkRole
        "element_name",
        "AttackPatternName",
        "TechniqueName",
    ],
    "text": [
        "text",
        "description",
        "descriptions",
        "definition",  # WorkRole
    ],
}


def get_standard_field_value(record: Dict[str, Any], field: str) -> Any:
    """Return the first present value for a logical field (uid/title/text) from a result record."""
    candidates = STANDARD_FIELD_CANDIDATES.get(field, [])
    for key in candidates:
        val = record.get(key)
        if val is not None and val != "" and val != "N/A":
            return val
    # Q031: Cypher may return dotted column names (e.g. wr.uid, wr.definition) when no AS alias.
    # Recognize those so suitability and Phase 2 accept WorkRole (and similar) rows.
    if field == "uid":
        for k, v in record.items():
            if (k.endswith(".uid") or k == "uid") and v and v != "N/A":
                return v
    elif field == "title":
        for k, v in record.items():
            if (
                (
                    k in ("role_name", "title", "name")
                    or k.endswith(".title")
                    or k.endswith(".name")
                    or k.endswith(".work_role")
                )
                and v
                and v != "N/A"
            ):
                return v
    elif field == "text":
        for k, v in record.items():
            if (
                (
                    k in ("text", "definition", "description")
                    or k.endswith(".definition")
                    or k.endswith(".text")
                    or k.endswith(".description")
                )
                and v
                and v != "N/A"
            ):
                return v
    return record.get(candidates[0]) if candidates else None


# --- Helpers: WorkRole shape detection (for Phase 2 / suitability) ---


def record_has_work_role_shape(record: Dict[str, Any]) -> bool:
    """True if record has WorkRole-shaped data (name-like + description-like or uid) per schema."""
    title_candidates = STANDARD_FIELD_CANDIDATES.get("title", [])
    text_candidates = STANDARD_FIELD_CANDIDATES.get("text", [])
    has_name = any(
        record.get(k)
        for k in title_candidates
        if record.get(k) not in (None, "", "N/A")
    )
    # Also accept dotted/alias name keys (e.g. role_name from Cypher AS role_name)
    if not has_name:
        has_name = any(
            v
            for k, v in record.items()
            if (
                k in ("role_name",)
                or k.endswith(".name")
                or k.endswith(".title")
                or k.endswith(".work_role")
            )
            and v not in (None, "", "N/A")
        )
    has_desc = any(
        record.get(k) for k in text_candidates if record.get(k) not in (None, "", "N/A")
    )
    # Q031: WorkRole rows may have wr.uid + role_name but null definition; still treat as work role shape.
    has_uid = get_standard_field_value(record, "uid") not in (None, "", "N/A")
    return bool(has_name and (has_desc or has_uid))


