# -----------------------------------------------------------------------------
# Compact metadata for database.get_status and is_small_dataset (counts only)
# -----------------------------------------------------------------------------

TECHNIQUE_METADATA: Dict[str, Any] = {
    "total_count": 201,  # Base techniques (stable)
}

# SubTechnique metadata
SUBTECHNIQUE_METADATA: Dict[str, Any] = {
    "total_count": 472,  # Stable
}

# Weakness metadata (CWE)
WEAKNESS_METADATA: Dict[str, Any] = {
    "total_count": 986,  # Relatively stable
}

# AttackPattern metadata (CAPEC)
ATTACKPATTERN_METADATA: Dict[str, Any] = {
    "total_count": 577,  # Relatively stable
}

# Task, Knowledge, Skill metadata (from NICE/DCWF)
TASK_METADATA: Dict[str, Any] = {
    "total_count": 1000,  # Approximate - would need to query for exact
    "note": "Query dynamically - count may vary",
}

KNOWLEDGE_METADATA: Dict[str, Any] = {
    "total_count": 1000,  # Approximate
    "note": "Query dynamically - count may vary",
}

SKILL_METADATA: Dict[str, Any] = {
    "total_count": 1000,  # Approximate
    "note": "Query dynamically - count may vary",
}


# -----------------------------------------------------------------------------
# API: WorkRole helpers, is_small_dataset, get_dataset_metadata
# -----------------------------------------------------------------------------


def get_workrole_count() -> int:
    """Get total WorkRole count from cache."""
    return WORKROLE_METADATA["total_count"]


def get_workrole_count_by_source() -> Dict[str, int]:
    """Get WorkRole counts by source (DCWF, NICE)."""
    return {
        source: info["count"] for source, info in WORKROLE_METADATA["sources"].items()
    }


def get_workrole_property_coverage() -> Dict[str, Dict[str, Any]]:
    """Get WorkRole property coverage information."""
    return WORKROLE_METADATA["property_coverage"]


def get_workrole_relationship_stats() -> Dict[str, Dict[str, Any]]:
    """Get WorkRole relationship statistics."""
    return WORKROLE_METADATA["relationship_stats"]


def is_small_dataset(label: str) -> bool:
    """Check if a dataset is small enough to cache metadata."""
    metadata_map = {
        "WorkRole": WORKROLE_METADATA,
        "SpecialtyArea": SPECIALTYAREA_METADATA,
        "Tactic": TACTIC_METADATA,
        "Ability": ABILITY_METADATA,
        "Technique": TECHNIQUE_METADATA,
        "SubTechnique": SUBTECHNIQUE_METADATA,
        "Weakness": WEAKNESS_METADATA,
        "AttackPattern": ATTACKPATTERN_METADATA,
    }

    if label in metadata_map:
        total = metadata_map[label].get("total_count", 0)
        return total < SMALL_DATASET_THRESHOLD

    return False


def get_dataset_metadata(label: str) -> Dict[str, Any]:
    """Get cached metadata for a dataset label."""
    metadata_map = {
        "WorkRole": WORKROLE_METADATA,
        "SpecialtyArea": SPECIALTYAREA_METADATA,
        "Tactic": TACTIC_METADATA,
        "Ability": ABILITY_METADATA,
        "Technique": TECHNIQUE_METADATA,
        "SubTechnique": SUBTECHNIQUE_METADATA,
        "Weakness": WEAKNESS_METADATA,
        "AttackPattern": ATTACKPATTERN_METADATA,
    }

    return metadata_map.get(label, {})
